import app from 'flarum/forum/app';
import Component from 'flarum/common/Component';
export default class AdFirstDiscussionEnd extends Component {
  view() {
    const enabled = app.forum.attribute('dashzeveg-ads-manager.ad_first_discussion_end_enabled');
    if (!enabled) return null;
    const random = app.forum.attribute('dashzeveg-ads-manager.ad_first_discussion_end_random');
    const desktopAds = [];
    const mobileAds = [];
    for (let i = 1; i <= 5; i++) {
      const desktop = app.forum.attribute(`dashzeveg-ads-manager.ad_first_discussion_end_desktop${i}`);
      const mobile = app.forum.attribute(`dashzeveg-ads-manager.ad_first_discussion_end_mobile${i}`);
      if (desktop && desktop.trim()) desktopAds.push(desktop);
      if (mobile && mobile.trim()) mobileAds.push(mobile);
    }
    let desktopHtml = '';
    let mobileHtml = '';
    if (random) {
      if (desktopAds.length) desktopHtml = desktopAds[Math.floor(Math.random() * desktopAds.length)];
      if (mobileAds.length) mobileHtml = mobileAds[Math.floor(Math.random() * mobileAds.length)];
    } else {
      desktopHtml = desktopAds[0];
      mobileHtml = mobileAds[0];
    }
    return m('div', {
      className: 'AdFirstDiscussionEnd'
    }, [m('div', {
      className: 'AdFirstDiscussionEnd-desktop',
      oncreate: vnode => {
        vnode.dom.innerHTML = desktopHtml;
      },
      onupdate: vnode => {
        vnode.dom.innerHTML = desktopHtml;
      }
    }), m('div', {
      className: 'AdFirstDiscussionEnd-mobile',
      oncreate: vnode => {
        vnode.dom.innerHTML = mobileHtml;
      },
      onupdate: vnode => {
        vnode.dom.innerHTML = mobileHtml;
      }
    })]);
  }
}
flarum.reg.add('dashzeveg-ads-manager', 'forum/components/AdFirstDiscussionEnd', AdFirstDiscussionEnd);